function buildFixtures() {
  const fixtures: Array<Record<string, unknown>> = [];

  for (const pair of PAIRS) {
    const seeds = SOURCE_SEEDS[pair.source];
    if (!seeds || seeds.length !== 50) {
      throw new Error(`Expected exactly 50 seeds for source ${pair.source}, got ${seeds?.length ?? 0}`);
    }

    seeds.forEach((seed, index) => {
      const id = `${pair.source}-${pair.target}-long-${String(index + 1).padStart(2, '0')}`;
      const fixture: Record<string, unknown> = {
        id,
        sourceText: seed.selectedText,
        sourceLanguage: pair.source,
        targetLanguage: pair.target,
        bookContext: seed.context,
      };

      if (pair.target === 'en' && seed.expectedEn) {
        fixture.expectedFields = { translation: seed.expectedEn };
      }

      fixtures.push(fixture);
    });
  }

  return fixtures;
}

